SELECT COUNT(upvote_id) AS upvote_count
FROM upvotes
WHERE content_id = 0;

SELECT user_id, MAX(reputation_score) AS max_reputation
FROM user_reputation
GROUP BY user_id;

SELECT reputation_score
FROM user_reputation
WHERE user_id = 1;

SELECT COUNT(flag_id) AS user_flag_count
FROM flags
WHERE user_id = 1;
